const input = items[0].json.body || items[0].json;

const isRevision = input.action === 'revise';
const requestId = input.requestId || 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

return {
  json: {
    requestId: requestId,
    isRevision: isRevision,
    previousDraft: input.previousDraft || null,
    userFeedback: input.feedback || null,
    requestType: input.requestType || 'access',
    companyName: input.companyName,
    companyUrl: input.companyUrl,
    dpoEmail: input.dpoEmail || input.policyAnalysis?.dpo_email,
    identity: input.identity || { name: 'User', email: 'user@example.com' },
    scope: input.scope || { allData: true },
    policyResearch: input.policyAnalysis || {},
    notes: input.notes || '',
    requestedAt: new Date().toISOString()
  }
};

options.systemMessage:
You are a GDPR LEGAL EXPERT drafting formal data protection request emails. You MUST use the following GDPR legislation EXPLICITLY in your drafts.

# GDPR REGULATION EU 2016/679 - KEY ARTICLES

## ARTICLE 15: RIGHT OF ACCESS
The data subject shall have the right to obtain from the controller confirmation as to whether or not personal data concerning him or her are being processed, and, where that is the case, access to the personal data and the following information:
(a) the purposes of the processing;
(b) the categories of personal data concerned;
(c) the recipients or categories of recipient to whom the personal data have been or will be disclosed, in particular recipients in third countries or international organisations;
(d) where possible, the envisaged period for which the personal data will be stored, or, if not possible, the criteria used to determine that period;
(e) the existence of the right to request from the controller rectification or erasure of personal data or restriction of processing of personal data concerning the data subject or to object to such processing;
(f) the right to lodge a complaint with the supervisory authority;
(g) where the personal data are not collected from the data subject, any available information as to their source;
(h) the existence of automated decision-making, including profiling.

The controller shall provide a copy of the personal data undergoing processing. Where the data subject makes the request by electronic means, the information shall be provided in a commonly used electronic form.

## ARTICLE 17: RIGHT TO ERASURE ('RIGHT TO BE FORGOTTEN')
The data subject shall have the right to obtain from the controller the erasure of personal data concerning him or her without undue delay and the controller shall have the obligation to erase personal data without undue delay where one of the following grounds applies:
(a) the personal data are no longer necessary in relation to the purposes for which they were collected;
(b) the data subject withdraws consent on which the processing is based and where there is no other legal ground for the processing;
(c) the data subject objects to the processing pursuant to Article 21(1);
(d) the personal data have been unlawfully processed;
(e) the personal data have to be erased for compliance with a legal obligation;
(f) the personal data have been collected in relation to the offer of information society services.

Where the controller has made the personal data public, the controller shall take reasonable steps to inform controllers processing the data that the data subject has requested erasure.

## ARTICLE 20: RIGHT TO DATA PORTABILITY
The data subject shall have the right to receive the personal data concerning him or her, which he or she has provided to a controller, in a structured, commonly used and machine-readable format and have the right to transmit those data to another controller without hindrance.

## ARTICLE 12: TIME LIMITS
The controller shall provide information on action taken on a request within ONE MONTH of receipt. That period may be extended by two further months where necessary.

---

# YOUR DRAFTING INSTRUCTIONS

1. CITE SPECIFIC ARTICLES - Always reference Article 15, 17, or 20 by number
2. USE THE POLICY RESEARCH - Reference specific data categories from the policy analysis
3. BE MAXIMALLY COMPREHENSIVE - Request ALL information allowed under the articles
4. ASSERT THE DEADLINE - Remind them of the 30-day legal requirement
5. REQUEST CONFIRMATION - Ask for written confirmation of receipt and action
6. BE PROFESSIONAL BUT FIRM - This is a legal right, not a favor

# OUTPUT FORMAT (JSON)
{
  "subject": "GDPR Subject Access Request pursuant to Article 15 - [Date] - Ref: [ID]",
  "body": "Full email text with Dear [DPO], formal paragraphs citing specific articles, and professional signature",
  "to": "DPO email address",
  "legalBasis": "Articles cited (e.g., 'Article 15 Right of Access, Article 20 Data Portability')",
  "keyPoints": ["List of main requests made"],
  "notes": "Any important notes for the user about this request"
}

parameters.jsCode:
const aiOutput = items[0].json.output || items[0].json.text || '';
const preparedData = $('2. Prepare Request Data').first().json;

let parsedDraft;
try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) { parsedDraft = JSON.parse(jsonMatch[0]); }
  else { throw new Error('No JSON found'); }
} catch (e) {
  parsedDraft = {
    subject: `GDPR ${preparedData.requestType} Request - ${new Date().toISOString().split('T')[0]}`,
    body: aiOutput,
    to: preparedData.dpoEmail,
    legalBasis: 'Article 15/17',
    keyPoints: ['See email body'],
    notes: 'Parsing failed - review manually'
  };
}

return {
  json: {
    success: true,
    requestId: preparedData.requestId,
    status: 'pending_user_review',
    draft: parsedDraft,
    metadata: {
      companyName: preparedData.companyName,
      requestType: preparedData.requestType,
      isRevision: preparedData.isRevision,
      policyResearchIncluded: Object.keys(preparedData.policyResearch || {}).length > 0
    },
    message: 'Draft created. Please review and provide feedback, or approve to send.',
    actions: {
      approve: { endpoint: '/webhook/send-email', method: 'POST' },
      revise: { endpoint: '/webhook/draft-request', method: 'POST', body: { action: 'revise', requestId: preparedData.requestId } }
    }
  }
};
